#include "delaunay_triangulation.h"
#include <stdlib.h>

typedef struct {
    int x;
    int y;
} Point;

static int compare_points(const void *a, const void *b) {
    const Point *pa = (const Point *)a;
    const Point *pb = (const Point *)b;
    if (pa->x != pb->x) {
        return pa->x - pb->x;
    }
    return pa->y - pb->y;
}

static long long cross(const Point *o, const Point *a, const Point *b) {
    return (long long)(a->x - o->x) * (b->y - o->y)
        - (long long)(a->y - o->y) * (b->x - o->x);
}

static int convex_hull_vertex_count(Point *points, int n) {
    if (n <= 1) {
        return n;
    }

    qsort(points, n, sizeof(Point), compare_points);

    Point *hull = (Point *)malloc((2 * n) * sizeof(Point));
    int k = 0;

    for (int i = 0; i < n; i++) {
        while (k >= 2 && cross(&hull[k - 2], &hull[k - 1], &points[i]) <= 0) {
            k--;
        }
        hull[k++] = points[i];
    }

    int lower_size = k;
    for (int i = n - 2; i >= 0; i--) {
        while (k > lower_size && cross(&hull[k - 2], &hull[k - 1], &points[i]) <= 0) {
            k--;
        }
        hull[k++] = points[i];
    }

    free(hull);
    return k - 1;
}

int delaunay_triangulation(int *arr, int len) {
    if (len <= 0) {
        return 0;
    }

    int n = arr[0];
    if (n < 3 || len < 1 + 2 * n) {
        return 0;
    }

    Point *points = (Point *)malloc(n * sizeof(Point));
    for (int i = 0; i < n; i++) {
        points[i].x = arr[1 + 2 * i];
        points[i].y = arr[1 + 2 * i + 1];
    }

    int hull_vertices = convex_hull_vertex_count(points, n);
    free(points);

    int triangle_count = 2 * n - 2 - hull_vertices;
    return triangle_count > 0 ? triangle_count : 0;
}

#include <algorithm>
#include <vector>

namespace {
struct Point {
    int x;
    int y;
};

bool operator<(const Point& lhs, const Point& rhs) {
    if (lhs.x != rhs.x) {
        return lhs.x < rhs.x;
    }
    return lhs.y < rhs.y;
}

bool operator==(const Point& lhs, const Point& rhs) {
    return lhs.x == rhs.x && lhs.y == rhs.y;
}

long long cross(const Point& a, const Point& b, const Point& c) {
    return static_cast<long long>(b.x - a.x) * (c.y - a.y)
        - static_cast<long long>(b.y - a.y) * (c.x - a.x);
}

std::vector<Point> build_convex_hull(std::vector<Point> points) {
    std::sort(points.begin(), points.end());
    points.erase(std::unique(points.begin(), points.end()), points.end());

    if (points.size() <= 1) {
        return points;
    }

    std::vector<Point> hull;
    hull.reserve(points.size() * 2);

    for (const Point& point : points) {
        while (hull.size() >= 2 && cross(hull[hull.size() - 2], hull.back(), point) <= 0) {
            hull.pop_back();
        }
        hull.push_back(point);
    }

    std::size_t lower_size = hull.size();
    for (std::size_t index = points.size() - 1; index > 0; --index) {
        const Point& point = points[index - 1];
        while (hull.size() > lower_size && cross(hull[hull.size() - 2], hull.back(), point) <= 0) {
            hull.pop_back();
        }
        hull.push_back(point);
    }

    if (!hull.empty()) {
        hull.pop_back();
    }

    return hull;
}
}  // namespace

int delaunay_triangulation(std::vector<int> arr) {
    if (arr.empty()) {
        return 0;
    }

    int point_count = arr[0];
    if (point_count < 3 || static_cast<int>(arr.size()) < 1 + point_count * 2) {
        return 0;
    }

    std::vector<Point> points;
    points.reserve(point_count);
    for (int index = 0; index < point_count; ++index) {
        points.push_back(Point{arr[1 + 2 * index], arr[1 + 2 * index + 1]});
    }

    std::sort(points.begin(), points.end());
    points.erase(std::unique(points.begin(), points.end()), points.end());
    if (points.size() < 3) {
        return 0;
    }

    int total_vertices = static_cast<int>(points.size());
    int hull_vertices = static_cast<int>(build_convex_hull(points).size());
    int triangles = 2 * total_vertices - 2 - hull_vertices;
    return std::max(0, triangles);
}

using System;

public class DelaunayTriangulation
{
    public static int Compute(int[] arr)
    {
        int n = arr[0];
        if (n < 3) return 0;

        double[] px = new double[n], py = new double[n];
        for (int i = 0; i < n; i++)
        {
            px[i] = arr[1 + 2 * i];
            py[i] = arr[1 + 2 * i + 1];
        }

        double EPS = 1e-9;
        int count = 0;

        for (int i = 0; i < n; i++)
        {
            for (int j = i + 1; j < n; j++)
            {
                for (int k = j + 1; k < n; k++)
                {
                    double ax = px[i], ay = py[i];
                    double bx = px[j], by = py[j];
                    double cx = px[k], cy = py[k];

                    double d = 2.0 * (ax * (by - cy) + bx * (cy - ay) + cx * (ay - by));
                    if (Math.Abs(d) < EPS) continue;

                    double ux = ((ax*ax + ay*ay) * (by - cy) +
                                 (bx*bx + by*by) * (cy - ay) +
                                 (cx*cx + cy*cy) * (ay - by)) / d;
                    double uy = ((ax*ax + ay*ay) * (cx - bx) +
                                 (bx*bx + by*by) * (ax - cx) +
                                 (cx*cx + cy*cy) * (bx - ax)) / d;

                    double rSq = (ux - ax) * (ux - ax) + (uy - ay) * (uy - ay);

                    bool valid = true;
                    for (int m = 0; m < n; m++)
                    {
                        if (m == i || m == j || m == k) continue;
                        double distSq = (ux - px[m]) * (ux - px[m]) + (uy - py[m]) * (uy - py[m]);
                        if (distSq < rSq - EPS) { valid = false; break; }
                    }

                    if (valid) count++;
                }
            }
        }

        return count;
    }
}

