func DelaunayTriangulation(arr []int) int {
	n := arr[0]
	if n < 3 {
		return 0
	}

	px := make([]float64, n)
	py := make([]float64, n)
	for i := 0; i < n; i++ {
		px[i] = float64(arr[1+2*i])
		py[i] = float64(arr[1+2*i+1])
	}

	eps := 1e-9
	count := 0

	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			for k := j + 1; k < n; k++ {
				ax, ay := px[i], py[i]
				bx, by := px[j], py[j]
				cx, cy := px[k], py[k]

				d := 2.0 * (ax*(by-cy) + bx*(cy-ay) + cx*(ay-by))
				if math.Abs(d) < eps {
					continue
				}

				ux := ((ax*ax+ay*ay)*(by-cy) + (bx*bx+by*by)*(cy-ay) + (cx*cx+cy*cy)*(ay-by)) / d
				uy := ((ax*ax+ay*ay)*(cx-bx) + (bx*bx+by*by)*(ax-cx) + (cx*cx+cy*cy)*(bx-ax)) / d

				rSq := (ux-ax)*(ux-ax) + (uy-ay)*(uy-ay)

				valid := true
				for m := 0; m < n; m++ {
					if m == i || m == j || m == k {
						continue
					}
					distSq := (ux-px[m])*(ux-px[m]) + (uy-py[m])*(uy-py[m])
					if distSq < rSq-eps {
						valid = false
						break
					}
				}

				if valid {
					count++
				}
			}
		}
	}

	return count
}

public class DelaunayTriangulation {

    public static int delaunayTriangulation(int[] arr) {
        int n = arr[0];
        if (n < 3) return 0;
        int hullSize = convexHullSize(arr, n);
        return Math.max(0, 2 * n - 2 - hullSize);
    }

    private static int convexHullSize(int[] arr, int n) {
        int[] order = new int[n];
        for (int i = 0; i < n; i++) {
            order[i] = i;
        }

        for (int i = 0; i < n; i++) {
            int best = i;
            for (int j = i + 1; j < n; j++) {
                int bx = arr[1 + 2 * best];
                int by = arr[1 + 2 * best + 1];
                int jx = arr[1 + 2 * j];
                int jy = arr[1 + 2 * j + 1];
                if (jx < bx || (jx == bx && jy < by)) {
                    best = j;
                }
            }
            int temp = order[i];
            order[i] = order[best];
            order[best] = temp;
        }

        int[] hull = new int[2 * n];
        int size = 0;

        for (int idx : order) {
            while (size >= 2 && cross(arr, hull[size - 2], hull[size - 1], idx) <= 0) {
                size--;
            }
            hull[size++] = idx;
        }

        int lowerSize = size;
        for (int i = n - 2; i >= 0; i--) {
            int idx = order[i];
            while (size > lowerSize && cross(arr, hull[size - 2], hull[size - 1], idx) <= 0) {
                size--;
            }
            hull[size++] = idx;
        }

        return Math.max(1, size - 1);
    }

    private static long cross(int[] arr, int a, int b, int c) {
        long ax = arr[1 + 2 * a];
        long ay = arr[1 + 2 * a + 1];
        long bx = arr[1 + 2 * b];
        long by = arr[1 + 2 * b + 1];
        long cx = arr[1 + 2 * c];
        long cy = arr[1 + 2 * c + 1];
        return (bx - ax) * (cy - ay) - (by - ay) * (cx - ax);
    }
}

fun delaunayTriangulation(arr: IntArray): Int {
    val n = arr[0]
    if (n < 3) return 0

    val points = MutableList(n) { index ->
        intArrayOf(arr[1 + 2 * index], arr[1 + 2 * index + 1])
    }
    points.sortWith(compareBy<IntArray> { it[0] }.thenBy { it[1] })

    fun cross(a: IntArray, b: IntArray, c: IntArray): Long {
        return (b[0] - a[0]).toLong() * (c[1] - a[1]) - (b[1] - a[1]).toLong() * (c[0] - a[0])
    }

    val lower = mutableListOf<IntArray>()
    for (point in points) {
        while (lower.size >= 2 && cross(lower[lower.size - 2], lower[lower.size - 1], point) <= 0L) {
            lower.removeAt(lower.lastIndex)
        }
        lower.add(point)
    }

    val upper = mutableListOf<IntArray>()
    for (index in points.indices.reversed()) {
        val point = points[index]
        while (upper.size >= 2 && cross(upper[upper.size - 2], upper[upper.size - 1], point) <= 0L) {
            upper.removeAt(upper.lastIndex)
        }
        upper.add(point)
    }

    val hullSize = lower.size + upper.size - 2
    return 2 * n - 2 - hullSize
}

pub fn delaunay_triangulation(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    if n < 3 { return 0; }

    let px: Vec<f64> = (0..n).map(|i| arr[1 + 2 * i] as f64).collect();
    let py: Vec<f64> = (0..n).map(|i| arr[1 + 2 * i + 1] as f64).collect();

    let eps = 1e-9;
    let mut count = 0;

    for i in 0..n {
        for j in (i+1)..n {
            for k in (j+1)..n {
                let (ax, ay) = (px[i], py[i]);
                let (bx, by) = (px[j], py[j]);
                let (cx, cy) = (px[k], py[k]);

                let d = 2.0 * (ax * (by - cy) + bx * (cy - ay) + cx * (ay - by));
                if d.abs() < eps { continue; }

                let ux = ((ax*ax + ay*ay) * (by - cy) +
                          (bx*bx + by*by) * (cy - ay) +
                          (cx*cx + cy*cy) * (ay - by)) / d;
                let uy = ((ax*ax + ay*ay) * (cx - bx) +
                          (bx*bx + by*by) * (ax - cx) +
                          (cx*cx + cy*cy) * (bx - ax)) / d;

                let r_sq = (ux - ax) * (ux - ax) + (uy - ay) * (uy - ay);

                let mut valid = true;
                for m in 0..n {
                    if m == i || m == j || m == k { continue; }
                    let dist_sq = (ux - px[m]) * (ux - px[m]) + (uy - py[m]) * (uy - py[m]);
                    if dist_sq < r_sq - eps { valid = false; break; }
                }

                if valid { count += 1; }
            }
        }
    }

    count
}

object DelaunayTriangulation {

  def delaunayTriangulation(arr: Array[Int]): Int = {
    val n = arr(0)
    if (n < 3) return 0

    val px = Array.tabulate(n)(i => arr(1 + 2 * i).toDouble)
    val py = Array.tabulate(n)(i => arr(1 + 2 * i + 1).toDouble)

    val eps = 1e-9
    var count = 0

    for (i <- 0 until n; j <- (i + 1) until n; k <- (j + 1) until n) {
      val (ax, ay) = (px(i), py(i))
      val (bx, by) = (px(j), py(j))
      val (cx, cy) = (px(k), py(k))

      val d = 2.0 * (ax * (by - cy) + bx * (cy - ay) + cx * (ay - by))
      if (math.abs(d) >= eps) {
        val ux = ((ax*ax + ay*ay) * (by - cy) +
                  (bx*bx + by*by) * (cy - ay) +
                  (cx*cx + cy*cy) * (ay - by)) / d
        val uy = ((ax*ax + ay*ay) * (cx - bx) +
                  (bx*bx + by*by) * (ax - cx) +
                  (cx*cx + cy*cy) * (bx - ax)) / d

        val rSq = (ux - ax) * (ux - ax) + (uy - ay) * (uy - ay)

        val valid = (0 until n).forall { m =>
          m == i || m == j || m == k || {
            val distSq = (ux - px(m)) * (ux - px(m)) + (uy - py(m)) * (uy - py(m))
            distSq >= rSq - eps
          }
        }

        if (valid) count += 1
      }
    }

    count
  }
}

import Foundation

func delaunayTriangulation(_ arr: [Int]) -> Int {
    let n = arr[0]
    if n < 3 { return 0 }

    var points: [(Int, Int)] = []
    for i in 0..<n {
        points.append((arr[1 + 2 * i], arr[1 + 2 * i + 1]))
    }
    points.sort { lhs, rhs in
        lhs.0 == rhs.0 ? lhs.1 < rhs.1 : lhs.0 < rhs.0
    }

    func cross(_ a: (Int, Int), _ b: (Int, Int), _ c: (Int, Int)) -> Int {
        (b.0 - a.0) * (c.1 - a.1) - (b.1 - a.1) * (c.0 - a.0)
    }

    var lower: [(Int, Int)] = []
    for point in points {
        while lower.count >= 2 && cross(lower[lower.count - 2], lower[lower.count - 1], point) <= 0 {
            lower.removeLast()
        }
        lower.append(point)
    }

    var upper: [(Int, Int)] = []
    for point in points.reversed() {
        while upper.count >= 2 && cross(upper[upper.count - 2], upper[upper.count - 1], point) <= 0 {
            upper.removeLast()
        }
        upper.append(point)
    }

    let hullVertexCount = max(0, lower.count + upper.count - 2)
    let triangleCount = 2 * n - 2 - hullVertexCount
    return max(0, triangleCount)
}

export function delaunayTriangulation(arr: number[]): number {
    const n = arr[0];
    if (n < 3) return 0;

    const points: Array<[number, number]> = [];
    for (let i = 0; i < n; i++) {
        points.push([arr[1 + 2 * i], arr[1 + 2 * i + 1]]);
    }

    points.sort((a, b) => a[0] - b[0] || a[1] - b[1]);

    function cross(a: [number, number], b: [number, number], c: [number, number]): number {
        return (b[0] - a[0]) * (c[1] - a[1]) - (b[1] - a[1]) * (c[0] - a[0]);
    }

    const lower: Array<[number, number]> = [];
    for (const point of points) {
        while (lower.length >= 2 && cross(lower[lower.length - 2], lower[lower.length - 1], point) <= 0) {
            lower.pop();
        }
        lower.push(point);
    }

    const upper: Array<[number, number]> = [];
    for (let i = points.length - 1; i >= 0; i--) {
        const point = points[i];
        while (upper.length >= 2 && cross(upper[upper.length - 2], upper[upper.length - 1], point) <= 0) {
            upper.pop();
        }
        upper.push(point);
    }

    const hullSize = lower.length + upper.length - 2;
    return 2 * n - 2 - hullSize;
}
